{
  "mode": "method",
  "tests": [
    {
      "name": "test_music_library_selection",
      "input": {
        "selected_song": "Artist A - Song 1"
      },
      "output": {
        "audio_player": {
          "input_mp3": "Artist A - Song 1",
          "output_mp3": "Artist A - Song 1 Infused",
          "download_link": "/downloads/Artist_A_Song_1_Infused.mp3"
        },
        "spectrographs": {
          "before": "spectrograph_A_Artist_A_Song_1.png",
          "after": "spectrograph_B_Artist_A_Song_1.png",
          "metrics": {
            "gamma_inclusion": "95%",
            "theta_inclusion": "90%",
            "gamma_40hz_adherence": "100%",
            "processing_time": "2s"
          }
        }
      },
      "notes": "Validates the music library selection and processing functionality."
    },
    {
      "name": "test_upload_own_mp3",
      "input": {
        "uploaded_file": "user_uploaded_song.mp3"
      },
      "output": {
        "audio_player": {
          "input_mp3": "user_uploaded_song.mp3",
          "output_mp3": "user_uploaded_song_Infused.mp3",
          "download_link": "/downloads/user_uploaded_song_Infused.mp3"
        },
        "spectrographs": {
          "before": "spectrograph_A_user_uploaded_song.png",
          "after": "spectrograph_B_user_uploaded_song.png",
          "metrics": {
            "gamma_inclusion": "92%",
            "theta_inclusion": "88%",
            "gamma_40hz_adherence": "99%",
            "processing_time": "3s"
          }
        }
      },
      "notes": "Tests the upload functionality and processing of a custom MP3 file."
    },
    {
      "name": "test_empty_upload",
      "input": {
        "uploaded_file": ""
      },
      "output": {
        "error": "No file uploaded"
      },
      "notes": "Ensures the system handles empty uploads gracefully."
    },
    {
      "name": "test_invalid_file_format",
      "input": {
        "uploaded_file": "invalid_file.txt"
      },
      "output": {
        "error": "Invalid file format. Please upload an MP3 file."
      },
      "notes": "Validates that only MP3 files can be processed."
    },
    {
      "name": "test_large_file_upload",
      "input": {
        "uploaded_file": "large_song.mp3"
      },
      "output": {
        "audio_player": {
          "input_mp3": "large_song.mp3",
          "output_mp3": "large_song_Infused.mp3",
          "download_link": "/downloads/large_song_Infused.mp3"
        },
        "spectrographs": {
          "before": "spectrograph_A_large_song.png",
          "after": "spectrograph_B_large_song.png",
          "metrics": {
            "gamma_inclusion": "90%",
            "theta_inclusion": "85%",
            "gamma_40hz_adherence": "98%",
            "processing_time": "10s"
          }
        }
      },
      "notes": "Tests the system's ability to handle large MP3 files."
    },
    {
      "name": "test_no_music_library_selection",
      "input": {
        "selected_song": null
      },
      "output": {
        "error": "No song selected from the music library."
      },
      "notes": "Checks the response when no song is selected from the library."
    },
